mapper.select:
SELECT * FROM booking
WHERE user_id = #{userId}
ORDER BY requested_at DESC

mapper.insert:
INSERT INTO booking (
    id, user_id, lesson_id, availability_id, title, requested_at, memo, zoom_join_url
) VALUES (
    UUID(), #{userId}, #{lessonId}, #{availabilityId}, #{title}, NOW(), #{memo}, #{zoomJoinUrl}
)

mapper.update:
UPDATE booking
SET title = #{title},
    memo = #{memo},
    zoom_join_url = #{zoomJoinUrl}
WHERE id = #{id}

UPDATE booking
SET confirmed_at = NOW()
WHERE id = #{id}

UPDATE booking
SET paid_at = NOW()
WHERE id = #{id}

UPDATE booking
SET paid_at = NULL
WHERE id = #{id}

UPDATE booking
SET availability_id = #{availabilityId}
WHERE id = #{id}
